function removeGreekAccentsAndToUpper(e){const o={ά:"Α",έ:"Ε",ή:"Η",ί:"Ι",ό:"Ο",ύ:"Υ",ώ:"Ω",Ά:"Α",Έ:"Ε",Ή:"Η",Ί:"Ι",Ό:"Ο",Ύ:"Υ",Ώ:"Ω",ϊ:"Ι",ΐ:"Ι",ϋ:"Υ",ΰ:"Υ",Ϊ:"Ι",Ϋ:"Υ"};return e.split("").map((function(e){return o[e]||e})).join("").toUpperCase()}document.addEventListener("DOMContentLoaded",(function(){const e=document.getElementById("symbash"),o=document.getElementById("kathgoria_symbashs"),n=document.getElementById("eidikothta_symbashs");var t,a;e.addEventListener("change",(async()=>{const n=e.value;if(t=n,o.innerHTML='<option value="" selected></option>',o.disabled=!0,n)try{const e=await fetch(`/api/kathgoriesSymbaseon/${n}`);(await e.json()).forEach((e=>{const n=new Option(e.kodikos.padEnd(10," ")+e.perigrafh,e.kodikos);o.appendChild(n)})),o.disabled=!1}catch(e){console.error(e)}})),o.addEventListener("change",(async()=>{const e=o.value;if(a=e,n.innerHTML='<option value="" selected></option>',n.disabled=!0,e)try{const o=await fetch(`/api/eidikothtesSymbaseon/${t}${e}`),a=await o.json();console.log(a),a.forEach((e=>{const o=new Option(e.kodikos.padEnd(10," ")+e.perigrafh,e.kodikos);n.appendChild(o)})),n.disabled=!1}catch(e){console.error(e)}})),n.addEventListener("change",(async()=>{const e=n.value;document.getElementById("kodikosSymbashs").value=t,document.getElementById("kodikosKathgorias").value=a,document.getElementById("kodikosEidikothtas").value=e})),(async()=>{e.innerHTML='<option value="" selected></option>';try{const o=await fetch("/api/symbaseis");let n;(await o.json()).forEach((o=>{n=removeGreekAccentsAndToUpper(o.perigrafh);const t=new Option(o.kodikos.padEnd(10," ")+n,o.kodikos);e.appendChild(t)}))}catch(e){console.error(e)}})()}));